import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import Stripe from 'stripe';

export interface ChargeResult {
  chargeId: string;
  status: string;
}

export interface RefundResult {
  refundId: string;
  status: string;
}

export interface PaymentService {
  createCharge(amount: number, currency: string, source: string, description?: string): Promise<ChargeResult>;
  createRefund(chargeId: string, amount?: number): Promise<RefundResult>;
}

@Injectable()
export class StripePaymentService implements PaymentService {
  private readonly logger = new Logger(StripePaymentService.name);
  private readonly stripe: Stripe;
  private readonly defaultCurrency = 'usd';

  constructor(private readonly configService: ConfigService) {
    const secretKey = this.configService.getOrThrow<string>('STRIPE_SECRET_KEY');
    this.stripe = new Stripe(secretKey, { apiVersion: '2023-10-16' });
    this.logger.log('Payment client initialized (stripe)');
  }

  async createCharge(
    amount: number,
    currency?: string,
    source = '',
    description = '',
  ): Promise<ChargeResult> {
    const useCurrency = currency ?? this.defaultCurrency;
    this.logger.log(`Creating charge amount=${amount} currency=${useCurrency}`);
    const charge = await this.stripe.charges.create({
      amount,
      currency: useCurrency,
      source,
      description,
    });
    return { chargeId: charge.id, status: charge.status };
  }

  async createRefund(
    chargeId: string,
    amount?: number,
  ): Promise<RefundResult> {
    this.logger.log(`Creating refund chargeId=${chargeId}`);
    const params: Stripe.RefundCreateParams = { charge: chargeId };
    if (amount !== undefined) {
      params.amount = amount;
    }
    const refund = await this.stripe.refunds.create(params);
    return { refundId: refund.id, status: refund.status ?? 'unknown' };
  }
}
